const { query, short_term, limit = 3 } = $json;
const shortTermContext = Array.isArray(short_term) ? short_term.slice(-10) : [];
return { query, short_term: shortTermContext, limit };

const { short_term, query } = $json;
const recentSummary = short_term.map((msg, i) => `[${i}] ${typeof msg === 'string' ? msg.slice(0, 200) : JSON.stringify(msg).slice(0, 200)}`);
return { short_term_summary: recentSummary, window_size: short_term.length, mode: 'short_term_window' };

const longTerm = $node['Stream LTM Search'].json;
const shortTerm = $node['Short-Term Window'].json;
return {
  query: $json.query,
  long_term_memories: longTerm.results || [],
  short_term_window: shortTerm.short_term_summary || [],
  total_long_term: longTerm.total || 0,
  recent_turns: shortTerm.window_size || 0,
  hybrid: true,
  recommendation: longTerm.total > 0
    ? 'Found relevant long-term context. Use LTM results for cross-session awareness.'
    : 'No LTM matches. Rely on short-term window + fresh exploration.'
};
